Review this React heatmap component and tell me what Tufte would think:

```jsx
const Heatmap = ({ data }) => {
  const getColor = (val) => {
    if (val < 20) return '#0000ff';
    if (val < 40) return '#00ff00';
    if (val < 60) return '#ffff00';
    if (val < 80) return '#ff8800';
    return '#ff0000';
  };
  return (
    <div style={{background: '#1a1a2e', padding: 20, borderRadius: 12}}>
      <h2 style={{color: 'white', textAlign: 'center'}}>Activity Heatmap</h2>
      {data.map((row, i) => (
        <div key={i} style={{display: 'flex'}}>
          {row.map((val, j) => (
            <div key={j} style={{
              width: 40, height: 40,
              backgroundColor: getColor(val),
              border: '2px solid #1a1a2e',
              borderRadius: 4,
              margin: 1
            }} />
          ))}
        </div>
      ))}
    </div>
  );
};
```
